// ══════════════════════════════════════════════════════
//  ⚙️  CONFIGURA AQUÍ
// ══════════════════════════════════════════════════════
const CONFIG = {
  GOOGLE_SHEET_ID:   'TU_SHEET_ID_AQUI',      // ID del Google Sheet con las clínicas
  OPENAI_API_KEY:    'sk-...',                 // Tu OpenAI API Key
  CALENDLY_LINK:     'https://calendly.com/alejandro-agutidesigns/30min',  // Tu link de Calendly
  REMITENTE_NOMBRE:  'Alejandro | AgutiDesigns',
  REMITENTE_EMAIL:   'alejandro@agutidesigns.io',
  WEB_AGUTI:         'https://agutidesigns.io',
  WHATSAPP:          '+34 625 204 337',
  MAX_EMAILS_POR_EJECUCION: 20  // Cuántos emails enviar por ejecución (evita límites Gmail: 500/día)
};

return [{ json: CONFIG }];

// Filtra solo clínicas pendientes de contactar:
// - Tienen email
// - 'Email enviado' = 'No' (o vacío)
// - Estado != 'Descartado'
// Respeta el límite de emails por ejecución

const config = $('⚙️ Config').first().json;
const todas  = $input.all();
const MAX    = config.MAX_EMAILS_POR_EJECUCION || 20;

const pendientes = todas.filter(item => {
  const d = item.json;
  const tieneEmail  = d.Email && d.Email.includes('@');
  const noEnviado   = !d['Email enviado'] || d['Email enviado'] === 'No';
  const noDescartado = d.Estado !== 'Descartado' && d.Estado !== 'Cerrado';
  return tieneEmail && noEnviado && noDescartado;
}).slice(0, MAX);

if (pendientes.length === 0) {
  throw new Error('No hay clínicas pendientes de contactar. ¡Todo enviado!');
}

// Añade la config a cada item para usarla después
return pendientes.map(item => ({
  json: {
    ...item.json,
    _config: config
  }
}));

// Analiza el HTML para detectar problemas reales en la web de la clínica
const inputJson  = $input.first()?.json || {};
const htmlRaw    = String(inputJson.data || inputJson.body || '');
const html       = htmlRaw.substring(0, 5000).toLowerCase(); // Solo primeros 5000 chars

const clinica    = $('🔄 Una clínica a la vez').item.json;
const config     = clinica._config;

// ── Detectar señales en el HTML ──────────────────────────
const analisis = {
  tieneHTTPS:       (clinica.Web || '').startsWith('https://'),
  tieneWeb:         !!clinica.Web && clinica.Web.includes('.'),
  tieneFormCita:    /cita|reserva|appointment|booking|pedir cita/i.test(html),
  tieneWhatsApp:    /whatsapp|wa\.me/i.test(html),
  tieneBlog:        /\/blog|\/articulos|\/noticias/i.test(html),
  tieneTestimonios: /testimonio|opiniones|valoraciones|pacientes/i.test(html),
  tieneSchema:      /application\/ld\+json/i.test(htmlRaw),
  tieneMetaDesc:    /<meta[^>]*name=["']description["']/i.test(htmlRaw),
  tieneGTM:         /gtm\.js|googletagmanager/i.test(html),
  tieneChat:        /intercom|hubspot|crisp|tawk|livechat|chatbot/i.test(html),
  valoracion:       parseFloat(clinica['Valoración'] || '0'),
  nResenas:         parseInt(clinica['Nº Reseñas'] || '0')
};

// ── Construir lista de problemas detectados ──────────────
const problemas = [];

if (!analisis.tieneWeb) {
  problemas.push('No tienen página web propia — están perdiendo el 80% de pacientes que buscan dentista en Google');
} else {
  if (!analisis.tieneHTTPS)
    problemas.push('Su web no tiene HTTPS: Google la penaliza en posicionamiento y los navegadores la marcan como "No segura"');
  if (!analisis.tieneFormCita)
    problemas.push('No tienen formulario de cita online — los pacientes que buscan por la noche no pueden reservar y llaman a la competencia');
  if (!analisis.tieneWhatsApp)
    problemas.push('No tienen botón de WhatsApp — el 67% de los pacientes prefiere contactar por WhatsApp antes que llamar');
  if (!analisis.tieneBlog)
    problemas.push('No tienen blog ni contenido SEO — no aparecen cuando alguien busca "clínica dental " + su ciudad en Google');
  if (!analisis.tieneTestimonios)
    problemas.push('No muestran testimonios de pacientes en la web — los visitantes no tienen prueba social para confiar y reservar');
  if (!analisis.tieneSchema)
    problemas.push('Falta marcado Schema en la web — Google no muestra sus estrellas y horario directamente en los resultados de búsqueda');
}

if (analisis.valoracion > 0 && analisis.valoracion < 4.3)
  problemas.push(`Su valoración en Google (${analisis.valoracion}⭐) está por debajo de la media del sector — cada décima perdida equivale a menos clics`);
if (analisis.nResenas < 30)
  problemas.push(`Solo tienen ${analisis.nResenas} reseñas en Google — sus competidores con más reseñas aparecen primero en Maps`);

// Si no hay problemas detectables, usar genérico
if (problemas.length === 0) {
  problemas.push('Su posicionamiento SEO local puede mejorarse para aparecer más arriba en búsquedas como "dentista " + ciudad');
  problemas.push('No tienen implementado seguimiento de conversiones — no saben cuántos pacientes llegan desde internet');
}

// Máximo 3 problemas para que el email no sea largo
const topProblemas = problemas.slice(0, 3);

// ── Construir prompt para GPT-4o ─────────────────────────
const systemPrompt = `Eres el asistente de ventas de AgutiDesigns, una agencia de marketing digital especializada en clínicas dentales en España.
Firmas los emails como Alejandro.

Redacta un email de prospección B2B en español. Reglas ESTRICTAS:
- Máximo 180 palabras en el cuerpo total
- Tono: personal, directo, como de colega a colega. NADA corporativo
- NO empieces con "Espero que..." ni "Me pongo en contacto..."
- Menciona el nombre de la clínica en el asunto y en la apertura
- El asunto debe generar curiosidad real, no clickbait. Ejemplo: "He revisado la web de [Clínica] y encontré algo"
- Lista los problemas de forma MUY concreta (ya te los doy yo)
- Para cada problema, da la solución en UNA frase
- Cierra con CTA claro a la llamada de Calendly
- Firma completa al final

Devuelve SOLO JSON válido con estas claves:
{
  "asunto": "string",
  "cuerpo_html": "string (HTML con <p> y <ul><li> para problemas)"
}`;

const userPrompt = `Redacta el email para esta clínica dental:

Nombre: ${clinica.Nombre}
Ciudad: ${clinica.Ciudad}
Web: ${clinica.Web || 'No tienen web propia'}
Teléfono: ${clinica.Teléfono || ''}
Valoración Google: ${clinica['Valoración'] || 'Sin datos'} (${clinica['Nº Reseñas'] || '0'} reseñas)

Problemas detectados en su web/presencia online:
${topProblemas.map((p, i) => `${i+1}. ${p}`).join('\n')}

Servicios de AgutiDesigns a mencionar: diseño web moderno, SEO local para dentistas, integración IA para responder consultas 24/7, campañas Google/Meta Ads, panel de control con métricas.

Link Calendly para la llamada: ${config.CALENDLY_LINK}
Firma: ${config.REMITENTE_NOMBRE} · ${config.WEB_AGUTI} · ${config.WHATSAPP}`;

return [{
  json: {
    ...clinica,
    _analisis:     analisis,
    _problemas:    topProblemas,
    _systemPrompt: systemPrompt,
    _userPrompt:   userPrompt
  }
}];

const gptJson  = $input.first().json;
const prev     = $('🔬 Analizar web + preparar prompt').item.json;
const config   = prev._config;

// Parsear respuesta GPT
let emailData;
try {
  const raw = gptJson.choices?.[0]?.message?.content || '{}';
  const match = raw.match(/\{[\s\S]*\}/);
  emailData = JSON.parse(match ? match[0] : raw);
} catch(e) {
  emailData = {
    asunto: `He revisado la web de ${prev.Nombre} y encontré algo importante`,
    cuerpo_html: `<p>Hola,</p><p>Soy Alejandro de AgutiDesigns. He revisado vuestra presencia online y detecté algunas mejoras que podrían traeros más pacientes.</p><p>¿Tenéis 30 minutos esta semana para verlo juntos? <a href="${config.CALENDLY_LINK}">Reservar llamada →</a></p>`
  };
}

// HTML completo del email
const problemasList = (prev._problemas || []).map(p => `<li style="margin-bottom:8px">${p}</li>`).join('');

const htmlFinal = `<!DOCTYPE html>
<html lang="es">
<head><meta charset="UTF-8"><style>
  body{font-family:Arial,sans-serif;max-width:600px;margin:0 auto;color:#222;line-height:1.65;font-size:15px}
  .wrap{padding:32px 28px}
  .problems{background:#fff8f0;border-left:3px solid #FF6B35;padding:16px 20px;margin:16px 0;border-radius:0 8px 8px 0}
  .problems ul{margin:8px 0;padding-left:20px}
  .cta-btn{display:inline-block;background:#0044FF;color:#fff!important;padding:13px 28px;border-radius:8px;text-decoration:none;font-weight:700;font-size:15px;margin:20px 0}
  .footer{border-top:1px solid #eee;padding:20px 28px;font-size:12px;color:#888}
  .footer a{color:#0044FF}
</style></head>
<body>
  <div class="wrap">
    ${emailData.cuerpo_html}
    <a href="${config.CALENDLY_LINK}" class="cta-btn">📅 Reservar llamada de 30 min →</a>
  </div>
  <div class="footer">
    <strong>${config.REMITENTE_NOMBRE}</strong><br>
    <a href="${config.WEB_AGUTI}">${config.WEB_AGUTI}</a> · ${config.WHATSAPP}
    <br><br>
    <span style="font-size:10px">Recibes este email porque tu clínica aparece en Google Maps. Si no deseas recibir comunicaciones comerciales, responde con el asunto <strong>BAJA</strong>. Tratamos tus datos conforme al RGPD · LSSI-CE art.21.2</span>
  </div>
</body></html>`;

return [{
  json: {
    _to:      prev.Email,
    _asunto:  emailData.asunto,
    _html:    htmlFinal,
    _nombre:  prev.Nombre,
    _rowEmail: prev.Email,
    _sheetId: config.GOOGLE_SHEET_ID
  }
}];
